        return _mutmut_trampoline(object.__getattribute__(self, 'xǁGenerationGateMiddlewareǁ__init____mutmut_orig'), object.__getattribute__(self, 'xǁGenerationGateMiddlewareǁ__init____mutmut_mutants'), args, kwargs, self)

